 * Assumes both arrays have the same length k.
 * Time complexity: O(k^2) brute force check.
 */
function isCyclicPermutation(A, S_i) {
    const k = A.length;
    if (k === 0) return true;

    // Brute force check: test all k possible rotations of S_i
    for (let j = 0; j < k; j++) { // j is the shift amount (start index in S_i)
        let match = true;
        for (let t = 0; t < k; t++) {
            // Element A[t] must match S_i rotated by j at position t
            // The element from S_i that ends up at position t is S_i[(t + j) % k]
            if (A[t] !== S_i[(t + j) % k]) {
                match = false;
                break;
            }
        }
        if (match) {
            return true;
        }
    }
    return false;
}


function solve(nums) {
    const n = nums.length;
    if (n === 0) return 0;

    // 1. Target sorted array S
    const S = [...nums].sort((a, b) => a - b);

    let totalSum = 0;

    // 2. Find all divisors k of n
    const divisors = new Set();
    for (let k = 1; k * k <= n; k++) {
        if (n % k === 0) {
            divisors.add(k);
            divisors.add(n / k);
        }
    }

    const K = Array.from(divisors);

    // 3. Check each divisor k
    for (const k of K) {
        let isSortable = true;

        // Case k=1: Each subarray is a single element. Sorting requires the original array to be sorted.
        if (k === 1) {
            for (let i = 1; i < n; i++) {
                if (nums[i] < nums[i - 1]) {
                    isSortable = false;
                    break;
                }
            }
        } else {
            // Check all N/k segments
            for (let i = 0; i * k < n; i++) {
                const start = i * k;

                // Extract A_i (from nums)
                const A_i = nums.slice(start, start + k);

                // Extract S_i (from S)
                const S_i = S.slice(start, start + k);

                // Check if A_i is a cyclic permutation of S_i
                if (!isCyclicPermutation(A_i, S_i)) {
                    isSortable = false;
                    break;
                }
            }
        }

        if (isSortable) {
            totalSum += k;
        }
    }

    return totalSum;
}

